use std::io::{self, Write};

struct WorkflowState {
    state: String,
    is_valid: bool,
}

impl WorkflowState {
    fn new(state: &str) -> Self {
        WorkflowState { state: state.to_string(), is_valid: true }
    }

    fn transition(&self, next_state: &str) -> Option<Self> {
        match (self.state.as_str(), next_state) {
            ("draft", "pending") => Some(WorkflowState::new("pending")),
            ("pending", "published") => Some(WorkflowState::new("published")),
            ("published", _) => None,
            (_, _) => None,
        }
    }
}

fn main() -> io::Result<()> {
    let mut workflow = WorkflowState::new("draft");
    println!("Initial State: {}", workflow.state);

    if let Some(next_workflow) = workflow.transition(&"pending") {
        println!("Transition successful: {}", next_workflow.state);
        let mut current_workflow = next_workflow;

        if let Some(final_workflow) = current_workflow.transition(&"published") {
            writeln!(io::stdout(), "Final State: {}", final_workflow.state)?;
        }
    }

    Ok(())
}

use std::collections::VecDeque;

struct RLEEncoder {
    data: Vec<i32>,
}

impl RLEEncoder {
    fn new(data: Vec<i32>) -> Self {
        RLEEncoder { data }
    }

    fn encode(&self) -> Vec<(i32, i32)> {
        let mut encoded_sequence = Vec::new();
        if self.data.is_empty() {
            return encoded_sequence;
        }

        let mut current_value = self.data[0];
        let mut count = 1;

        for i in 1..self.data.len() {
            if self.data[i] == current_value {
                count += 1;
            } else {
                encoded_sequence.push((current_value, count));
                current_value = self.data[i];
                count = 1;
            }
        }

        encoded_sequence.push((current_value, count));
        encoded_sequence
    }
}

fn main() {
    let measurements = vec![10, 10, 10, 25, 25, 30, 30, 30, 30, 30];
    let encoder = RLEEncoder::new(measurements);
    let compressed_data = encoder.encode();

    println!("Original Data: {:?}", vec![10, 10, 10, 25, 25, 30, 30, 30, 30, 30]);
    println!("RLE Encoded Pairs (Value, Count): ");
    for pair in compressed_data {
        print!("{}, {:?}; ", pair.0, pair.1);
    }
    println!("");
}

use std::fmt::Display;

struct FileState<'a> {
    name: &'a str,
    data: Vec<u8>,
}

impl Display for FileState<'_> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "FileState(name = \"{}\", size_bytes = {})", self.name, self.data.len())
    }
}

struct FileProcessor<'a> {
    file: FileState<'a>,
    is_ready_to_process: bool,
}

impl<'a> FileProcessor<'a> {
    fn new(file: FileState<'a>) -> Self {
        FileProcessor { 
            file,
            is_ready_to_process: false
        }
    }

    fn mark_as_scanned(&mut self) -> Result<(), &'static str> {
        if !self.is_ready_to_process {
            return Err("File must be scanned before processing.");
        }
        println!("Successfully processed: {}", self.file);
        Ok(())
    }

    fn set_scanning_status(&mut self, safe_flag: bool) -> Result<(), &'static str> {
        if safe_flag {
            self.is_ready_to_process = true;
            println!("File status updated: Ready for processing.");
            Ok(()) 
        } else {
            self.is_ready_to_process = false;
            Err("File blocked due to virus scan failure.")
        }
    }
}

fn main() {
    let raw_file = FileState { name: "document.zip", data: vec![1, 2, 3] };
    let mut processor = FileProcessor::new(raw_file);

    match processor.set_scanning_status(false) { 
        Ok(_) => (), 
        Err(e) => println!("Error setting status: {}", e) 
    }

    println!("Current state: {}", processor.file);

    match processor.set_scanning_status(true) { 
        Ok(_) => match processor.mark_as_scanned() { 
            Ok(_) => println!("Upload complete."),
            Err(e) => println!("Processing failed: {}", e),
        },
        Err(e) => println!("Cannot process yet: {}", e)
    }

