use std::fmt::{self, Display};
use std::io::{self, Write};

#[derive(Debug)]
enum VaultState {
    Uninitialized,
    Locked,
    Active,
}

struct PasswordVault {
    state: VaultState,
    encrypted_data: Option<Vec<u8>>,
}

impl PasswordVault {
    fn new() -> Self {
        PasswordVault {
            state: VaultState::Uninitialized,
            encrypted_data: None,
        }
    }

    fn initialize(&mut self) -> Result<(), &'static str> {
        if matches!(self.state, VaultState::Uninitialized) {
            println!("Executing initialization routine...");
            Ok(())
        } else {
            Err("Vault already initialized or in a different state.")
        }
    }

    fn lock_vault(&mut self) -> Result<(), &'static str> {
        if let VaultState::Uninitialized = self.state {}
        match self.initialize() {
            Ok(_) => {
                self.state = VaultState::Locked;
                println!("Vault successfully transitioned to LOCKED state.");
                Ok(())
            }
            Err(e) => Err(e),
        }
    }

    fn load_key_and_activate(&mut self, key_material: &[u8]) -> Result<(), &'static str> {
        if let VaultState::Locked = self.state {}
        if self.encrypted_data.is_none() {
            self.encrypted_data = Some(b"dummy_encrypted_payload".to_vec());
        }

        println!("Attempting key material injection and state promotion...");
        if key_material.len() > 0 {
            self.state = VaultState::Active;
            Ok(())
        } else {
            Err("Key material cannot be empty for activation.")
        }
    }

    fn get_status(&self) -> String {
        match self.state {
            VaultState::Uninitialized => "Status: Uninitialized".to_string(),
            VaultState::Locked => "Status: Locked (Requires Key Material)".to_string(),
            VaultState::Active => "Status: Active and Operational".to_string(),
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut vault = PasswordVault::new();
    println!("Initial State: {}", vault.get_status());

    vault.lock_vault()?;
    println!("Current State after Lock: {}", vault.get_status());

    let key_bytes = b"supersecretkey123".to_vec();
    vault.load_key_and_activate(&key_bytes)?;
    println!("Final State after Activation: {}", vault.get_status());

    Ok(())
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read};

struct Record {
    key: String,
    value: String,
}

fn process_file_batch(paths: &[String]) -> Result<Vec<Record>, io::Error> {
    let mut results = Vec::new();
    for path in paths {
        if !std::path::Path::new(path).exists() {
            continue;
        }
        match std::fs::read_to_string(path) {
            Ok(content) => {
                let mut lines = content.lines();
                let mut extracted_data: HashMap<String, String> = HashMap::new();
                while let Some(line) = lines.next() {
                    if line.contains(":") {
                        let parts: Vec<&str> = line.split(':').collect();
                        if parts.len() >= 2 {
                            let key = parts[0].trim().to_string();
                            let value = parts[1].trim().replace(' ', "");
                            extracted_data.insert(key, value);
                        }
                    }
                }
                for (k, v) in extracted_data {
                    results.push(Record { key: k, value: v });
                }
            },
            Err(e) => {
                eprintln!("Could not read file {}: {}", path, e);
            }
        }
    }
    Ok(results)
}
